 93 | const SUBSCRIPTION_PROVIDERS: &[&str] = &[
 94 |     // Subscription / OAuth providers (no per-token billing at all)
 95 |     "openai-codex",
 96 |     "github-copilot",
 97 |     "github-copilot-enterprise",
 98 |     "gemini-web",
 99 |     "local_cuda",
100 |     // Our hosted subscription providers (flat-rate, no per-token cost)
101 |     "zai",
102 |     "glm5",
103 | ];
104 | fn is_subscription_provider(p: &str) -> bool {
105 |     SUBSCRIPTION_PROVIDERS.contains(&p)
106 | }
107 | fn is_free_model_id(id: &str) -> bool {
108 |     let lower = id.to_ascii_lowercase();
109 |     lower.contains(":free") || lower.ends_with("-free")
110 | }
