112 | async fn is_free_or_eligible(model: &str, registry: &ProviderRegistry) -> bool {
113 |     let trimmed = model.trim();
114 |     if trimmed.is_empty() {
115 |         return false;
116 |     }
117 | 
118 |     let (provider_name, model_id) = parse_model_string(trimmed);
119 |     if provider_name.is_none() {
120 |         return is_free_model_id(trimmed);
121 |     }
122 | 
123 |     let pn = provider_name.unwrap();
124 |     if is_subscription_provider(&pn.to_ascii_lowercase()) || is_free_model_id(model_id) {
125 |         return true;
126 |     }
127 | 
128 |     let Some(p) = registry.get(pn) else {
129 |         return false;
130 |     };
131 |     match p.list_models().await {
132 |         Ok(ms) => ms.into_iter().any(|m| {
133 |             m.id.eq_ignore_ascii_case(model_id)
134 |                 && m.input_cost_per_million.unwrap_or(1.0) <= 0.0
135 |                 && m.output_cost_per_million.unwrap_or(1.0) <= 0.0
136 |         }),
137 |         Err(_) => false,
138 |     }
139 | }
