157 | async fn create_agent_session(name: &str, instructions: &str, model: &str) -> Result<Session> {
158 |     let mut session = Session::new().await.context("Failed to create session")?;
159 |     session.agent = name.to_string();
160 |     session.metadata.model = Some(model.to_string());
161 |     let system_msg = format!(
162 |         "You are @{name}, a specialized sub-agent. {instructions}\n\n\
163 |          You have access to all tools. Be thorough, focused, and concise. Complete the task fully."
164 |     );
165 |     session.add_message(Message {
166 |         role: Role::System,
167 |         content: vec![ContentPart::Text { text: system_msg }],
168 |     });
169 |     Ok(session)
170 | }
