176 | async fn handle_spawn(params: &Params) -> Result<ToolResult> {
177 |     let name = params.name.as_ref().context("name required for spawn")?;
178 |     let instructions = params
179 |         .instructions
180 |         .as_ref()
181 |         .context("instructions required for spawn")?;
182 |     let requested = params.model.as_ref().context("model required for spawn")?;
183 |     let current = params
184 |         .current_model
185 |         .clone()
186 |         .or_else(|| std::env::var("CODETETHER_DEFAULT_MODEL").ok())
187 |         .context("cannot determine caller model")?;
188 | 
189 |     // Policy: different model
190 |     if normalize_model(requested) == normalize_model(&current) {
191 |         return Ok(ToolResult::error(format!(
192 |             "Spawn blocked: '{requested}' must differ from '{current}'."
193 |         )));
194 |     }
195 | 
196 |     // Policy: free/subscription eligible
197 |     let registry = get_registry().await?;
198 |     if !is_free_or_eligible(requested, &registry).await {
199 |         return Ok(ToolResult::error(format!(
200 |             "Spawn blocked: '{requested}' is not free/subscription-eligible. \
201 |              Options: (1) OpenRouter ':free' models e.g. \
202 |              'meta-llama/llama-3.3-70b-instruct:free', 'qwen/qwen3-coder:free', 'openai/gpt-oss-120b:free'; \
203 |              (2) Our subscription providers: 'zai/<model>', 'glm5/<model>'; \
204 |              (3) OAuth providers: 'openai-codex/<model>', 'github-copilot/<model>', \
205 |              'gemini-web/<model>', 'local_cuda/<model>'."
206 |         )));
207 |     }
208 | 
209 |     if store::contains(name) {
210 |         return Ok(ToolResult::error(format!(
211 |             "Agent @{name} exists. Use kill first."
212 |         )));
213 |     }
214 | 
215 |     let session = create_agent_session(name, instructions, requested).await?;
216 |     store::insert(
217 |         name.clone(),
218 |         AgentEntry {
219 |             instructions: instructions.clone(),
220 |             session,
221 |         },
222 |     );
223 |     tracing::info!(agent = %name, "Sub-agent spawned");
224 |     Ok(ToolResult::success(format!(
225 |         "Spawned @{name} on '{requested}': {instructions}"
226 |     )))
227 | }
