129 | /// Safely parse a UUID string with explicit skip/warn behavior.
130 | /// Returns None and logs a warning if the string is not a valid UUID,
131 | /// preventing silent NIL UUID fallback that could corrupt data linkage.
132 | fn parse_uuid_guarded(s: &str, context: &str) -> Option<Uuid> {
133 |     match s.parse::<Uuid>() {
134 |         Ok(uuid) => Some(uuid),
135 |         Err(e) => {
136 |             tracing::warn!(
137 |                 context,
138 |                 uuid_str = %s,
139 |                 error = %e,
140 |                 "Invalid UUID string - skipping operation to prevent NIL UUID corruption"
141 |             );
142 |             None
143 |         }
144 |     }
145 | }
