275 | // SRP: event collection only
276 | async fn run_agent_loop(
277 |     rx: &mut mpsc::Receiver<SessionEvent>,
278 |     handle: tokio::task::JoinHandle<Result<crate::session::SessionResult>>,
279 | ) -> (String, String, Vec<Value>, Option<String>) {
280 |     let mut response = String::new();
281 |     let mut thinking = String::new();
282 |     let mut tools = Vec::new();
283 |     let mut error = None;
284 |     let mut done = false;
285 |     let start = std::time::Instant::now();
286 |     let max_wait = std::time::Duration::from_secs(300);
287 | 
288 |     while !done && start.elapsed() < max_wait {
289 |         tokio::task::yield_now().await;
290 | 
291 |         match tokio::time::timeout(std::time::Duration::from_millis(20), rx.recv()).await {
292 |             Ok(Some(event)) => match event {
293 |                 SessionEvent::TextComplete(t) => response.push_str(&t),
294 |                 SessionEvent::ThinkingComplete(t) => thinking.push_str(&t),
295 |                 SessionEvent::ToolCallComplete {
296 |                     name,
297 |                     output,
298 |                     success,
299 |                 } => {
300 |                     tools.push(json!({ "tool": name, "success": success, "output_preview": truncate_preview(&output, 200) }));
301 |                 }
302 |                 SessionEvent::Error(e) => {
303 |                     response.push_str(&format!("\n[Error: {e}]"));
304 |                     error = Some(e);
305 |                 }
306 |                 SessionEvent::Done => done = true,
307 |                 _ => {}
308 |             },
309 |             Ok(None) | Err(_) => {
310 |                 if handle.is_finished() {
311 |                     done = true;
312 |                 }
313 |             }
314 |         }
315 |     }
316 | 
317 |     // Task cleanup
318 |     if !handle.is_finished() {
319 |         handle.abort();
320 |         error = Some("Agent timed out after 5 minutes".into());
321 |     } else if let Ok(Err(e)) = handle.await {
322 |         error = Some(e.to_string());
323 |     }
324 | 
325 |     (response, thinking, tools, error)
326 | }
